func (o *ReportOrchestrator) RequestAndDownloadWithOptions(ctx context.Context, reportType string, marketplaceIDs []string, startTime, endTime string, options map[string]any, timeout time.Duration) ([]map[string]string, error) {
	if timeout <= 0 {
		timeout = defaultReportTimeout
	}
	spec := reportSpec{Type: reportType, StartTime: startTime, EndTime: endTime, Options: options}
	if len(marketplaceIDs) > 0 {
		spec.MarketplaceID = marketplaceIDs[0]
	}
	reportID, err := o.createReport(ctx, spec)
	if err != nil {
		return nil, err
	}
	documentID, err := o.pollUntilDone(ctx, reportID, timeout)
	if err != nil {
		return nil, err
	}
	data, err := o.DownloadReportDocument(ctx, documentID)
	if err != nil {
		return nil, err
	}
	if strings.Contains(reportType, "SALES_AND_TRAFFIC") {
		return salesTrafficRows(data)
	}
	return parseTSV(data)
}

func (o *ReportOrchestrator) FindLatestReports(ctx context.Context, reportType string, marketplaceIDs []string, limit int) ([]reportMeta, error) {
	if limit <= 0 {
		limit = 10
	}
	params := map[string]string{
		"reportTypes":        reportType,
		"processingStatuses": "DONE",
		"marketplaceIds":     strings.Join(marketplaceIDs, ","),
		"pageSize":           strconv.Itoa(limit),
	}
	o.progress("listing completed reports %s", reportType)
	raw, err := o.api.Get("/reports/2021-06-30/reports", params)
	if err != nil {
		return nil, err
	}
	reports := extractReportList(raw)
	if len(reports) == 0 {
		return nil, fmt.Errorf("no completed %s reports found", reportType)
	}
	if len(reports) > limit {
		reports = reports[:limit]
	}
	return reports, nil
}

func (o *ReportOrchestrator) FindLatestReportRows(ctx context.Context, reportType string, marketplaceIDs []string, limit int) ([]map[string]string, error) {
	reports, err := o.FindLatestReports(ctx, reportType, marketplaceIDs, limit)
	if err != nil {
		return nil, err
	}
	var out []map[string]string
	for _, meta := range reports {
		if meta.ReportDocumentID == "" {
			continue
		}
		data, err := o.DownloadReportDocument(ctx, meta.ReportDocumentID)
		if err != nil {
			return nil, err
		}
		rows, err := parseTSV(data)
		if err != nil {
			return nil, err
		}
		out = append(out, rows...)
	}
	if len(out) == 0 {
		return nil, fmt.Errorf("completed %s reports did not include downloadable rows", reportType)
	}
	return out, nil
}

func (o *ReportOrchestrator) DownloadReportDocument(ctx context.Context, reportDocumentID string) ([]byte, error) {
	path := "/reports/2021-06-30/documents/{reportDocumentId}"
	raw, err := o.api.Get(replacePathParam(path, "reportDocumentId", reportDocumentID), nil)
	if err != nil {
		return nil, err
	}
	url := jsonString(raw, "url")
	if url == "" {
		return nil, fmt.Errorf("report document %s response did not include url", reportDocumentID)
	}
	compression := strings.ToUpper(jsonString(raw, "compressionAlgorithm", "compression_algorithm"))
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
	if err != nil {
		return nil, err
	}
	o.progress("downloading report document %s", reportDocumentID)
	resp, err := o.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	if resp.StatusCode == http.StatusForbidden {
		return nil, fmt.Errorf("report document URL returned HTTP 403; the presigned URL may have expired, retry the command")
	}
	if resp.StatusCode >= 400 {
		return nil, fmt.Errorf("report document URL returned HTTP %d", resp.StatusCode)
	}
	limit := o.maxDownloadBytes
	if limit <= 0 {
		limit = maxReportDownloadBytes
	}
	data, err := io.ReadAll(io.LimitReader(resp.Body, limit+1))
	if err != nil {
		return nil, err
	}
	if int64(len(data)) > limit {
		return nil, fmt.Errorf("report document exceeds %d byte limit", limit)
	}
	if compression == "GZIP" {
		zr, err := gzip.NewReader(bytes.NewReader(data))
		if err != nil {
			return nil, fmt.Errorf("opening gzip report: %w", err)
		}
		defer zr.Close()
		data, err = io.ReadAll(io.LimitReader(zr, limit+1))
		if err != nil {
			return nil, fmt.Errorf("reading gzip report: %w", err)
		}
		if int64(len(data)) > limit {
			return nil, fmt.Errorf("decompressed report exceeds %d byte limit", limit)
		}
	}
	return data, nil
}

func (o *ReportOrchestrator) pollUntilDone(ctx context.Context, reportID string, timeout time.Duration) (string, error) {
	if timeout <= 0 {
		timeout = defaultReportTimeout
	}
	deadline := o.now().Add(timeout)
	for {
		raw, err := o.api.Get(replacePathParam("/reports/2021-06-30/reports/{reportId}", "reportId", reportID), nil)
		if err != nil {
			return "", err
		}
		status := strings.ToUpper(jsonString(raw, "processingStatus", "processing_status", "status"))
		switch status {
		case "DONE":
			doc := jsonString(raw, "reportDocumentId", "report_document_id")
			if doc == "" {
				return "", fmt.Errorf("report %s is DONE but has no reportDocumentId", reportID)
			}
			return doc, nil
		case "CANCELLED", "FATAL":
			return "", fmt.Errorf("report %s ended with status %s", reportID, status)
		case "", "IN_QUEUE", "IN_PROGRESS":
			o.progress("report %s status %s", reportID, status)
		default:
			o.progress("report %s status %s", reportID, status)
		}
		if !o.now().Before(deadline) {
			return "", fmt.Errorf("timed out after %s waiting for report %s", timeout, reportID)
		}
		if err := o.sleep(ctx, o.pollInterval); err != nil {
			return "", err
		}
	}
}

func (o *ReportOrchestrator) waitForCreateSlot(ctx context.Context) error {
	o.mu.Lock()
	if o.createMinGap <= 0 || o.lastCreate.IsZero() {
		o.mu.Unlock()
		return nil
	}
	wait := o.createMinGap - o.now().Sub(o.lastCreate)
	if wait <= 0 {
		o.mu.Unlock()
		return nil
	}
	o.mu.Unlock()
	o.progress("waiting %s for Reports API createReport rate limit", wait.Round(time.Second))
	return o.sleep(ctx, wait)
}

func (o *ReportOrchestrator) markCreate() {
	o.mu.Lock()
	defer o.mu.Unlock()
	o.lastCreate = o.now()
}

func (o *ReportOrchestrator) progress(format string, args ...any) {
	if o == nil || o.stderr == nil {
		return
	}
	fmt.Fprintf(o.stderr, format+"\n", args...)
}

func parseTSV(data []byte) ([]map[string]string, error) {
	data = bytes.TrimPrefix(data, []byte{0xEF, 0xBB, 0xBF})
	data = bytes.ReplaceAll(data, []byte("\r\n"), []byte("\n"))
	data = bytes.TrimSpace(data)
	if len(data) == 0 {
		return []map[string]string{}, nil
	}
	r := csv.NewReader(bytes.NewReader(data))
	r.Comma = '\t'
	r.FieldsPerRecord = -1
	r.LazyQuotes = true
	records, err := r.ReadAll()
	if err != nil {
		return nil, fmt.Errorf("parsing TSV: %w", err)
	}
	if len(records) == 0 {
		return []map[string]string{}, nil
	}
	headers := make([]string, len(records[0]))
	for i, h := range records[0] {
		headers[i] = normalizeReportHeader(h)
	}
	out := make([]map[string]string, 0, len(records)-1)
	for _, rec := range records[1:] {
		if len(rec) == 0 {
			continue
		}
		row := make(map[string]string, len(headers))
		for i, h := range headers {
			if h == "" {
				continue
			}
			if i < len(rec) {
				row[h] = strings.TrimSpace(rec[i])
			} else {
				row[h] = ""
			}
		}
		out = append(out, row)
	}
	return out, nil
}

func parseJSONReport(data []byte) (map[string]any, error) {
	var out map[string]any
	if err := json.Unmarshal(bytes.TrimPrefix(data, []byte{0xEF, 0xBB, 0xBF}), &out); err != nil {
		return nil, err
	}
	return out, nil
}

func normalizeReportHeader(s string) string {
	s = strings.TrimSpace(strings.TrimPrefix(s, "\ufeff"))
	s = strings.ToLower(s)
	replacer := strings.NewReplacer("-", "_", " ", "_", "/", "_", "(", "", ")", "", "%", "pct", ".", "", ":", "")
	s = replacer.Replace(s)
	for strings.Contains(s, "__") {
		s = strings.ReplaceAll(s, "__", "_")
	}
	return strings.Trim(s, "_")
}

func jsonString(raw json.RawMessage, keys ...string) string {
	var obj map[string]any
	if err := json.Unmarshal(raw, &obj); err != nil {
		return ""
	}
	for _, key := range keys {
		if v, ok := obj[key]; ok {
			switch t := v.(type) {
			case string:
				return t
			case float64:
				return strconv.FormatFloat(t, 'f', -1, 64)
			default:
				return fmt.Sprint(t)
			}
		}
	}
	return ""
}

func extractReportList(raw json.RawMessage) []reportMeta {
	var direct []map[string]any
	if json.Unmarshal(raw, &direct) == nil {
		return reportMetasFromObjects(direct)
	}
	var obj map[string]json.RawMessage
	if json.Unmarshal(raw, &obj) != nil {
		return nil
	}
	for _, key := range []string{"reports", "data", "items"} {
		if rawList, ok := obj[key]; ok {
			var list []map[string]any
			if json.Unmarshal(rawList, &list) == nil {
				return reportMetasFromObjects(list)
			}
		}
	}
	return nil
}

func reportMetasFromObjects(list []map[string]any) []reportMeta {
	out := make([]reportMeta, 0, len(list))
	for _, obj := range list {
		raw, _ := json.Marshal(obj)
		out = append(out, reportMeta{
			ReportID:         jsonString(raw, "reportId", "report_id"),
			ReportType:       jsonString(raw, "reportType", "report_type"),
			ProcessingStatus: jsonString(raw, "processingStatus", "processing_status"),
			ReportDocumentID: jsonString(raw, "reportDocumentId", "report_document_id"),
			CreatedTime:      jsonString(raw, "createdTime", "created_time"),
			DataStartTime:    jsonString(raw, "dataStartTime", "data_start_time"),
			DataEndTime:      jsonString(raw, "dataEndTime", "data_end_time"),
		})
	}
	return out
}

func salesTrafficRows(data []byte) ([]map[string]string, error) {
	report, err := parseJSONReport(data)
	if err != nil {
		return nil, err
	}
	var rows []map[string]string
	collectSalesTrafficRows("", report, &rows)
	return rows, nil
}

func collectSalesTrafficRows(prefix string, v any, rows *[]map[string]string) {
	switch t := v.(type) {
	case []any:
		for _, item := range t {
			if obj, ok := item.(map[string]any); ok {
				row := map[string]string{}
				flattenJSON(prefix, obj, row)
				if len(row) > 0 {
					*rows = append(*rows, row)
				}
			} else {
				collectSalesTrafficRows(prefix, item, rows)
			}
		}
	case map[string]any:
		for k, item := range t {
			collectSalesTrafficRows(k, item, rows)
		}
	}
}

func flattenJSON(prefix string, obj map[string]any, row map[string]string) {
	for k, v := range obj {
		key := normalizeReportHeader(k)
		if prefix != "" {
			key = normalizeReportHeader(prefix) + "_" + key
		}
		switch t := v.(type) {
		case map[string]any:
			flattenJSON(key, t, row)
		case []any:
			b, _ := json.Marshal(t)
			row[key] = string(b)
		default:
			row[key] = fmt.Sprint(t)
		}
	}
}

func reportDateRange(days int) (string, string) {
	if days <= 0 {
		days = 30
	}
	end := time.Now().UTC()
	start := end.AddDate(0, 0, -days)
	return start.Format(time.RFC3339), end.Format(time.RFC3339)
}

func novelSinceDate(days int) string {
	if days <= 0 {
		days = 30
	}
	return time.Now().UTC().AddDate(0, 0, -days).Format("2006-01-02")
}

func marketSpec(reportType, marketplaceID string, days int) reportSpec {
	start, end := reportDateRange(days)
	return reportSpec{Type: reportType, MarketplaceID: marketplaceID, StartTime: start, EndTime: end}
}

func optionalMarketSpec(reportType, marketplaceID string, days int) reportSpec {
	spec := marketSpec(reportType, marketplaceID, days)
	spec.Optional = true
	return spec
}

func salesTrafficSpecs(marketplaceID string, days int) []reportSpec {
	if days <= 0 {
		days = 30
	}
	if days > 30 {
		days = 30
	}
	var specs []reportSpec
	end := time.Now().UTC()
	remaining := days
	for remaining > 0 {
		span := min(remaining, 14)
		start := end.AddDate(0, 0, -span)
		specs = append(specs, reportSpec{
			Type:          "GET_SALES_AND_TRAFFIC_REPORT",
			MarketplaceID: marketplaceID,
			StartTime:     start.Format(time.RFC3339),
			EndTime:       end.Format(time.RFC3339),
		})
		end = start
		remaining -= span
	}
	return specs
}

func brandPeriodSpec(reportType, marketplaceID, period string) reportSpec {
	if period == "" {
		period = "WEEK"
	}
	return reportSpec{
		Type:          reportType,
		MarketplaceID: marketplaceID,
		Options:       map[string]any{"reportPeriod": strings.ToUpper(period)},
		MaxAge:        24 * time.Hour,
	}
}

func amountFrom(values ...string) float64 {
	for _, v := range values {
		v = strings.TrimSpace(strings.ReplaceAll(strings.ReplaceAll(v, "$", ""), ",", ""))
		if v == "" {
			continue
		}
		f, err := strconv.ParseFloat(v, 64)
		if err == nil {
			return f
		}
	}
	return 0
}

func intFrom(values ...string) int {
	for _, v := range values {
		v = strings.TrimSpace(strings.ReplaceAll(v, ",", ""))
		if v == "" {
			continue
		}
		i, err := strconv.Atoi(v)
		if err == nil {
			return i
		}
		f, err := strconv.ParseFloat(v, 64)
		if err == nil {
			return int(f)
		}
	}
	return 0
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if strings.TrimSpace(v) != "" {
			return strings.TrimSpace(v)
		}
	}
	return ""
}

func isBrandRegistryError(err error) bool {
	var api *client.APIError
	if errors.As(err, &api) {
		return api.StatusCode == http.StatusForbidden
	}
	return strings.Contains(err.Error(), "HTTP 403")
}
